import os
from PIL import Image
import torch
from torch.utils.data import Dataset

class FMoWDataset(Dataset):
    def __init__(self, data_dir, split='train', transform=None):
        self.data_dir = data_dir
        self.split = split
        self.transform = transform

        txt_file = os.path.join(data_dir, f'{split}.txt')
        region_file = os.path.join(data_dir, f'region_labels_{split}.txt')

        self.samples = []
        self.regions = []

        with open(txt_file, 'r') as f:
            for line in f:
                parts = line.strip().split()
                if len(parts) == 2:
                    self.samples.append((parts[0], int(parts[1])))
                elif len(parts) == 1:
                    self.samples.append((parts[0], -1))

        if os.path.exists(region_file):
            with open(region_file, 'r') as f:
                for line in f:
                    self.regions.append(int(line.strip()))
        else:
            self.regions = [-1] * len(self.samples)

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx):
        img_name, label = self.samples[idx]
        region = self.regions[idx]
        img_path = os.path.join(self.data_dir, 'images', img_name)
        image = Image.open(img_path).convert('RGB')

        if self.transform:
            image = self.transform(image)

        return image, label, region

class FMoWTestDataset(Dataset):
    def __init__(self, data_dir, transform=None):
        self.data_dir = data_dir
        self.transform = transform

        txt_file = os.path.join(data_dir, 'test.txt')
        self.samples = []
        with open(txt_file, 'r') as f:
            for line in f:
                img_name = line.strip()
                if img_name:
                    self.samples.append(img_name)

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx):
        img_name = self.samples[idx]
        img_path = os.path.join(self.data_dir, 'images', img_name)
        image = Image.open(img_path).convert('RGB')

        if self.transform:
            image = self.transform(image)

        return image, img_name
